// SUPPLEMENT — television and cable, the worldwide story. Where extra-television.js
// follows one country's spectrum-scarcity logic from 1925 to the streaming void, this file
// follows the rest of the world: state-controlled birth in Nazi Germany, Cold War
// divergence into a dozen different public/commercial/state models (Britain, France,
// Japan, the USSR, Italy, Brazil, South Africa), the satellite era that made broadcasting
// borderless (Eurovision, Telstar, Star TV, Al Jazeera, CCTV), and the streaming-era
// regulatory responses of the EU, Canada, India, Australia, Singapore, and Korea. Cross-
// links extra-television.js: tvprecursors, baird1925, colortv, cnn, backyarddish,
// netflixstreaming, digitaltransition, cordcutting, streamingwars, netneutrality, euquota,
// streamingvoid. No images for now — data only.
window.ATLAS_EVENTS.push(

{ id:"statetv1935", year:1935, date:"1935–1939", era:4, cat:["tv","power"],
  title:"State Television Before the War",
  wiki:"Fernsehsender Paul Nipkow",
  gallery:["Reichs-Rundfunk-Gesellschaft","1936 Summer Olympics"],
  summary:"Germany's Fernsehsender Paul Nipkow opens the world's first regular television service in March 1935 under Nazi state control; the 1936 Berlin Olympics become its first mass broadcast event, while France's state-run Ministry of PTT begins its own government television service the same year.",
  importance:"The Reich Broadcasting Corporation (RRG) had been brought under full Nazi control by 1934; the Paul Nipkow station it launched the next year used a 180-line system and broadcast to public viewing rooms — Fernsehstuben — rather than private sets, since almost no one owned one. The 1936 Olympics broadcasts, up to eight hours a day, were the medium's first mass demonstration anywhere. Meanwhile France's Ministry of PTT began its own broadcasts in 1935 — also government-run from the start, though without a propaganda mandate. Both nations chose state control of the new medium at its birth: the BBC's independent-but-public model, already running since 1929, was the exception, not the rule.",
  impact:{
    tv:"Television's first owners are governments, not markets or independent broadcasters.",
    power:"Nazi Germany seizes the new medium for mass persuasion from its first broadcast.",
    law:"State control of television is established as the global default at its birth." },
  causes:["tvprecursors","baird1925"], effects:["ortf","itvuk"] },

{ id:"itvuk", year:1955, date:"1954–1964", era:5, cat:["tv","law"],
  title:"Britain Ends the BBC's Monopoly",
  wiki:"ITV",
  gallery:["Television Act 1954","BBC2"],
  summary:"The Television Act 1954 creates the Independent Television Authority and licenses commercial stations; ITV goes on air in September 1955, the first time a major European country lets television compete with its state broadcaster rather than leaving it a monopoly.",
  importance:"Since 1936 the BBC, funded by license fee, had been Britain's only television service — the purest version of the public-service model. The 1954 Act, passed over objections that advertising would corrupt broadcasting, created a regulator to license regional commercial companies that were funded by advertising but bound to public-service duties: news, current affairs, regional programming. ITV's 1955 launch proved a national broadcaster could face competition without abandoning the underlying premise of public obligation. The dual system — one license-funded, one advertising-funded, both regulated for the public interest — became the template Britain extended again in 1982 with Channel 4, while the BBC itself kept broadcasting on the 405-line standard it had used since 1936 until BBC2's 1964 launch began the shift to 625 lines and UHF.",
  impact:{
    tv:"Commercial television is licensed for the first time alongside a public broadcaster.",
    law:"A regulator extends public-interest duties to advertising-funded broadcasters, not just the BBC.",
    power:"Broadcasting becomes a dual system rather than a single state or market monopoly." },
  causes:["baird1925","statetv1935"], effects:["channel4uk"] },

{ id:"ortf", year:1964, date:"1949–1987", era:5, cat:["tv","power"],
  title:"The Television of the President",
  wiki:"ORTF",
  gallery:["Radiodiffusion-télévision française","TF1"],
  summary:"France's state broadcaster evolves from RTF (1949) into the more centralized ORTF (1964) under de Gaulle, who treats television as a direct line to the nation — until the state monopoly itself ends in 1982 and TF1 is privatized in 1987.",
  importance:"From the Liberation, French television was an arm of the state, run first as RTF and then, after 1964, reorganized as ORTF with its news services brought under tighter executive influence. Charles de Gaulle used the medium as a direct broadcast channel to the French people, bypassing a press he distrusted — earning it the label 'the television of the president.' The arrangement outlasted de Gaulle but not the deregulatory wave of the 1980s: in 1982 the state monopoly formally ended and private channels were licensed, and in 1987 TF1, the flagship former state channel, was privatized outright. The brief, failed private channels La Cinq and TV6, both gone within a few years, showed how difficult the transition from total state control to a competitive market actually was.",
  impact:{
    power:"A head of state uses television as a direct, unmediated channel to citizens.",
    tv:"Decades of state broadcasting monopoly end in a rapid, turbulent privatization.",
    law:"Ending a state monopoly proves far harder than declaring it over." },
  causes:["statetv1935"], effects:["tvwf1989"] },

{ id:"nhkjapan", year:1953, date:"1953–1984", era:5, cat:"tv",
  title:"NHK and the Technological Showcase",
  wiki:"NHK",
  gallery:["1964 Summer Olympics"],
  summary:"Japan's public broadcaster NHK begins regular television in 1953, leads the world into color in 1960, showcases the nation's recovery at the 1964 Tokyo Olympics, and in 1983 launches the first direct-broadcast satellite TV service.",
  importance:"NHK, funded like the BBC by a receiver fee, became both Japan's public broadcaster and a demonstration platform for its postwar technological ambitions. Color broadcasting arrived in 1960, years ahead of much of Europe's standards debates; the 1964 Tokyo Olympics, broadcast live via satellite, presented a rebuilt Japan to a global audience and exported NHK's production standards alongside it. By 1983, NHK was operating the world's first direct-broadcast satellite TV service, delivering signals straight to home dishes without a terrestrial relay — a delivery method that would not become common in Europe or the U.S. for years. Each step paired public funding with a national project: prove that Japan could lead, not follow, in broadcast technology.",
  impact:{
    tv:"A receiver-fee public broadcaster doubles as a showcase for national technology.",
    power:"Television becomes the medium through which a rebuilt nation presents itself to the world.",
    technology:"Color broadcasting and direct satellite delivery are achieved years ahead of comparable economies." },
  causes:["tvprecursors"], effects:[] },

{ id:"soviettv", year:1951, date:"1938–1970", era:5, cat:["tv","power","surveillance"],
  title:"Soviet Central Television",
  wiki:"Soviet Central Television",
  gallery:["Ostankino Tower"],
  summary:"The USSR's Central Television, run by the state Gosteleradio committee, grows from its first regular broadcasts in 1938 into a propaganda instrument reaching roughly 90% of the Soviet population by 1970 — state television at continental scale.",
  importance:"Soviet television was never separated from the state that built it: Gosteleradio, the State Committee for Television and Radio, supervised all programming as an arm of government from the start. Regular programming from Moscow began in 1938 and expanded after the war into a 'central, republican, and regional' structure that could blanket the union's eleven time zones. By 1970 it reached roughly nine in ten Soviet households — a saturation rate achieved through state allocation of sets and signal rather than market demand. It is the starkest version of the pattern this gallery traces repeatedly: where Britain and France debated how much independence to grant television, the USSR never posed the question.",
  impact:{
    power:"A single state body controls television production and reception across a continental empire.",
    surveillance:"Near-universal television penetration is achieved through state allocation, not market demand.",
    tv:"Broadcasting at continental scale operates with no separation from the government that runs it." },
  causes:["statetv1935"], effects:[] },

{ id:"eurovisionsat", year:1962, date:"1954–1976", era:5, cat:["tv","radio"],
  title:"Satellites Make Television Borderless",
  wiki:"Eurovision (network)",
  gallery:["Telstar","Satellite Instructional Television Experiment"],
  summary:"The European Broadcasting Union's Eurovision network (1954) lets broadcasters share live feeds across borders; Telstar (1962) carries the first live transatlantic broadcasts; and India's satellite-relayed SITE project (1975) beams educational programming to 2,400 villages — three steps toward television without a national boundary.",
  importance:"Eurovision began as technical cooperation: European broadcasters agreeing to exchange news footage and live events over shared landlines and microwave links, the first time television crossed borders routinely rather than as a novelty. Telstar, an experimental American communications satellite, proved in 1962 that a single relay in orbit could carry a live signal across an ocean, making 'international broadcast' a real-time possibility rather than a delayed film reel. India's Satellite Instructional Television Experiment then turned the same technology toward development: for a year, a NASA satellite beamed educational programming directly to community sets in 2,400 villages that had never had television at all — the first large-scale demonstration that satellites could deliver television to places terrestrial infrastructure would never reach.",
  impact:{
    tv:"Television exchange across national borders becomes routine rather than exceptional.",
    technology:"A single satellite relay makes live intercontinental broadcasting technically possible.",
    power:"Satellite delivery lets broadcasters reach populations no domestic transmitter network covers." },
  causes:["baird1925"], effects:["startv"] },

{ id:"australiatv", year:1956, date:"1956", era:5, cat:"tv",
  title:"Australia Chooses Both",
  wiki:"Television in Australia",
  summary:"Australian television launches in Sydney and Melbourne in 1956, timed to the Melbourne Olympics, after years of debate between Britain's public-service model and America's commercial one — resolved by adopting both at once, a dual public/commercial system from day one.",
  importance:"Unlike Britain, which introduced commercial television only after two decades of BBC monopoly, Australia's first television licenses in 1956 went simultaneously to a public broadcaster (the ABC, modeled on the BBC) and to commercial stations funded by advertising (modeled on American networks). The delay itself was the story: years of parliamentary debate over which model to follow ended not in a choice but in an import of both systems side by side — a pattern that would recur as Australian media policy continued borrowing selectively from British and American precedent for the rest of the century, from broadcasting through to its later platform-bargaining experiments.",
  impact:{
    tv:"Public and commercial television are licensed simultaneously rather than in succession.",
    power:"A new broadcasting nation imports both major regulatory models rather than choosing one.",
    law:"Years of policy debate resolve into parallel systems instead of a single framework." },
  causes:["itvuk"], effects:["ausnewsmedia"] },

{ id:"palsecam", year:1967, date:"1967", era:5, cat:["tv","power"],
  title:"PAL, SECAM, and the Color Standards War",
  wiki:"PAL",
  gallery:["SECAM"],
  summary:"West Germany and Britain adopt the PAL color system in 1967; France, the same year, launches its own incompatible SECAM standard — a split driven as much by Gaullist resistance to German technology as by engineering, dividing Europe's television sets for decades.",
  importance:"Color television needed a transmission standard, and by the mid-1960s three incompatible systems were competing: America's NTSC, Germany's PAL, and France's SECAM. The technical differences were real but modest; the political stakes were not. France, under de Gaulle, rejected PAL specifically because it had been developed in Germany, and pushed SECAM as a demonstration of independent French — and, through licensing, Soviet — technological capability; the USSR adopted SECAM partly to avoid a Western-aligned standard. The result was a Europe divided by a line that had nothing to do with picture quality: a television bought in West Germany could not display color from a French broadcast, for as long as the analog era lasted.",
  impact:{
    tv:"Europe's television sets are divided by an incompatible color standard for decades.",
    power:"A technical standard is chosen to assert national independence rather than for engineering merit.",
    law:"Cross-border broadcasting compatibility becomes a casualty of geopolitical signaling." },
  causes:["colortv"], effects:[] },

{ id:"cancon", year:1970, date:"1970", era:5, cat:["tv","law","power"],
  title:"Canada Mandates Canadian Content",
  wiki:"Canadian content",
  summary:"The CRTC imposes the first systematic 'CanCon' quotas — minimum percentages of Canadian-made material that broadcasters must air — the first sustained attempt by any country to use broadcast regulation to protect a national culture from a much larger neighbor's media.",
  importance:"Canada's proximity to the United States meant American programming could simply cross the border on the same airwaves Canadian stations used, threatening to make Canadian television commercially indistinguishable from American television. The CRTC's content quotas, introduced in 1970, required broadcasters to air a minimum share of Canadian-produced programming — aimed not at any political message but at the existence of a domestic production industry at all. It was the first sustained instance of a country using broadcast regulation explicitly as cultural policy, a defensive measure against market gravity rather than against any single foreign actor — and it established the template, content quotas as cultural protection, that the EU adopted in 2016 and that Canada itself extended to streaming in 2023.",
  impact:{
    law:"Content quotas are used explicitly as cultural protection for the first time.",
    power:"A smaller media market regulates to resist absorption by its larger neighbor's output.",
    tv:"Domestic production is sustained by regulatory requirement rather than market demand alone." },
  causes:[], effects:["canadac11"] },

{ id:"italyrai", year:1976, date:"1974–1980", era:5, cat:["tv","power","law"],
  title:"Italy Breaks RAI's Monopoly",
  wiki:"RAI",
  gallery:["Mediaset","Silvio Berlusconi"],
  summary:"Italy's Constitutional Court rules in 1976 that RAI's state monopoly applies only to national broadcasting, not local stations — a loophole cable entrepreneur Silvio Berlusconi exploits by linking local stations into a de facto national network, building the media empire that would carry him to the premiership.",
  importance:"RAI, Italy's state broadcaster, had held a legally protected monopoly reaffirmed as recently as 1975. The Constitutional Court's 1976 ruling cracked it open by a technicality: the monopoly covered national broadcasting, but nothing in the law prevented local stations from operating — or prevented the same owner from running many local stations that, broadcasting identical programming simultaneously, functioned as a national network in all but name. Silvio Berlusconi, who had already built a cable system serving his own housing developments in the early 1970s, used exactly this loophole through his Fininvest holding company to assemble Canale 5, Italia 1, and Rete 4 — eventually Mediaset — into RAI's only real competitor. A court ruling about local frequencies became the foundation of a media empire, and that empire's owner became prime minister.",
  impact:{
    law:"A narrow court ruling about local stations is used to build a national network.",
    power:"A media empire built on a regulatory loophole produces a future head of government.",
    tv:"State monopoly gives way to private competition through judicial interpretation, not legislation." },
  causes:["itvuk"], effects:[] },

{ id:"channel4uk", year:1982, date:"1974–1984", era:5, cat:["tv","law"],
  title:"Channel 4 and the Hybrid Broadcaster",
  wiki:"Channel 4",
  gallery:["Annan Committee"],
  summary:"The Annan Committee's 1977 report recommends a fourth UK channel dedicated to programming ITV and the BBC would not make; Channel 4 launches in 1982, advertising-funded but structurally required to commission from independent producers. The Cable and Broadcasting Act 1984 then deregulates cable and opens it to foreign ownership.",
  importance:"Commissioned in 1974 to review the whole of British broadcasting, the Annan Committee reported in 1977 with a proposal unlike anything in the existing dual system: a fourth channel that would not produce its own programming but commission it entirely from independent producers, aimed at audiences ITV's mass-advertising model underserved. Channel 4, launching in 1982, became simultaneously a public-service institution and a commercial broadcaster — neither the BBC's license-fee model nor ITV's regional-franchise model, but a third hybrid built specifically to seed an independent production sector. Two years later, the Cable and Broadcasting Act took policy in the opposite direction for the newer medium, deregulating cable rates and — unlike America's contemporaneous cable rules — explicitly permitting foreign ownership of British cable systems.",
  impact:{
    tv:"A national broadcaster is structured to fund an independent production sector by design.",
    law:"Cable and terrestrial television are deregulated on opposite principles within two years.",
    power:"Foreign ownership of domestic cable systems is permitted where the US forbade it." },
  causes:["itvuk"], effects:["channel4debate"] },

{ id:"iranrevolutiontv", year:1979, date:"1979", era:5, cat:["tv","power"],
  title:"Television and the Iranian Revolution",
  wiki:"Iranian Revolution",
  summary:"State television, built up under the Shah as a symbol of modernization, becomes a battleground and then an instrument of the 1979 revolution — seized and repurposed within days to broadcast the new Islamic Republic's authority, showing how quickly a state's broadcast infrastructure can change hands and purpose.",
  importance:"Iran's national television network had been built as a showcase of the Shah's modernization program, reaching most of the country's urban population by the late 1970s. When the revolution arrived, that infrastructure — transmitters, studios, technical staff — did not need to be built by the new government; it needed only to be occupied. Within days of the Shah's departure, state television was broadcasting the symbols and voices of the Islamic Republic, instantly possessing the reach the previous government had spent two decades constructing. It was a vivid demonstration that broadcast infrastructure is politically neutral only until someone seizes the transmitter — a lesson Eastern Europe would relearn a decade later, and that would recur in coup attempts for decades after.",
  impact:{
    power:"Control of broadcast infrastructure transfers with the government, instantly and completely.",
    communications:"Television built to project one government's authority broadcasts its successor within days.",
    society:"A revolution's legitimacy is established in part through control of the airwaves." },
  causes:[], effects:["aljazeeratv"] },

{ id:"tvglobobrazil", year:1985, date:"1965–1989", era:5, cat:["tv","power"],
  title:"TV Globo and Brazilian Democracy",
  wiki:"TV Globo",
  summary:"Rede Globo, launched in 1965 and built into Brazil's dominant network under military rule, plays a contested but decisive role in covering the country's return to civilian elections in the late 1980s — a private network's news judgment shaping a fragile new democracy's first real choices.",
  importance:"TV Globo grew to national dominance during Brazil's military dictatorship (1964–1985), benefiting from the regime's telecommunications buildout and becoming, by audience share, one of the largest commercial networks in the world. When direct presidential elections returned in 1989 — the first since 1960 — Globo's news division was widely seen as having shaped public perception of the leading candidates, most controversially in its editing of the final debate before the runoff. The episode became a test case for a question this gallery returns to repeatedly: what happens when the dominant broadcaster in a young democracy is a private commercial entity with its own institutional history, rather than a state broadcaster subject to electoral oversight or a regulated public body answerable to a charter.",
  impact:{
    power:"A private network's editorial choices are widely credited with shaping a national election.",
    tv:"Commercial dominance built under authoritarian rule outlasts the regime that enabled it.",
    society:"A new democracy's first real choice is filtered through one company's newsroom." },
  causes:[], effects:[] },

{ id:"taiwantv", year:1987, date:"1987–1993", era:5, cat:["tv","power","law"],
  title:"Taiwan's Airwaves After Martial Law",
  wiki:"Mass media in Taiwan",
  summary:"The lifting of martial law in 1987 ends decades of state-controlled broadcasting in Taiwan; a previously unregulated cable industry — the so-called 'fourth channel' — is formally legalized only by the Cable Radio and Television Act of 1993, regulation arriving years after the practice it governs.",
  importance:"For nearly forty years under martial law, Taiwan's three terrestrial television networks were effectively organs of the ruling party and the state. When martial law ended in 1987, the formal monopoly broke down faster than the law could follow: an unlicensed cable industry had already grown to serve a large share of households by relaying foreign and pirated signals, operating in a legal vacuum. The 1993 Cable Radio and Television Act caught up by legalizing and licensing what was already there — de facto liberalization preceding de jure regulation, a pattern that distinguishes Taiwan's media transition from the top-down deregulation seen in Europe.",
  impact:{
    power:"A one-party broadcasting monopoly dissolves faster than a regulatory framework can replace it.",
    tv:"An unlicensed cable industry operates at scale before any law acknowledges it.",
    law:"Regulation legalizes a media market years after that market already exists." },
  causes:[], effects:[] },

{ id:"tiananmentv", year:1989, date:"1989", era:5, cat:["tv","power","surveillance"],
  title:"Tiananmen on Global Television",
  wiki:"1989 Tiananmen Square protests and massacre",
  summary:"International networks, including CNN, broadcast the Tiananmen Square protests live to a global audience via satellite — the Chinese government loses control of the narrative in real time, and over the following years builds some of the most extensive television and information controls of any major media market.",
  importance:"For weeks in the spring of 1989, foreign broadcasters used satellite uplinks — the same technology that had made Eurovision and Telstar possible decades earlier — to send live pictures of the Beijing protests around the world. The crackdown that followed was watched live by hundreds of millions outside China, a propaganda setback the government could not contain with the tools it had. The lesson the Chinese state drew was not to abandon international broadcasting but to master it: within years, China Central Television began building the global footprint and the domestic content controls — culminating decades later in 'Document No. 9' and a billion-dollar new headquarters — that this single event made urgent.",
  impact:{
    surveillance:"A government that loses control of a live broadcast resolves to build the tools never to again.",
    power:"International live broadcasting briefly removes a state's ability to control its own narrative.",
    communications:"Satellite television turns a domestic crackdown into a global, simultaneous event." },
  causes:["cnn"], effects:["cctvgoingout","documentno9"] },

{ id:"tvwf1989", year:1989, date:"1989", era:5, cat:["tv","law","power"],
  title:"Television Without Frontiers",
  wiki:"Television Without Frontiers",
  summary:"The European Community's Television Without Frontiers directive establishes the 'country of origin' principle — a broadcaster licensed in one EU state can transmit freely to all others — the first continent-wide broadcasting law, and the foundation every later EU media directive builds on.",
  importance:"As satellite and cable made it technically trivial for a broadcast licensed in one European country to reach viewers in another, the Community faced a choice: let every receiving country impose its own rules on incoming signals, fragmenting the market, or pick one country's rules to govern. Television Without Frontiers chose the latter — the 'country of origin' principle, under which a broadcaster need only satisfy the rules of the state that licensed it to transmit anywhere in the Community. It also introduced the EU's first content quotas, a 'majority European works' requirement that prefigured the much larger streaming quotas to come. Every subsequent EU broadcasting law — the renamed Audiovisual Media Services Directive of 2007, and its streaming-era revisions — is built on this 1989 foundation.",
  impact:{
    law:"A single member state's rules govern broadcasts received across an entire continent.",
    tv:"The first continent-wide broadcasting law replaces a patchwork of national rules.",
    power:"Content quotas protecting domestic production are written into European law for the first time." },
  causes:["ortf"], effects:["avmsd2007"] },

{ id:"cnneffect", year:1991, date:"1991", era:6, cat:["tv","power"],
  title:"The CNN Effect",
  wiki:"CNN effect",
  summary:"CNN's live, uninterrupted coverage of the 1991 Gulf War — reporters broadcasting from Baghdad as bombs fell — gives a single cable channel a seat at the table of war planning, coining the term 'CNN effect' for real-time media's influence on policy and military decisions.",
  importance:"CNN had launched in 1980 as a novelty — a channel that never went off air — but the Gulf War made it indispensable: its correspondents in Baghdad provided the only live pictures from inside a country at war with the United States, watched by the same officials directing that war. The 'CNN effect' named the resulting feedback loop — policymakers reacting to coverage of events their own agencies might not yet have confirmed, and adversaries timing actions for the news cycle. It marked the moment a privately owned, advertising-funded cable channel became a de facto participant in international diplomacy and military strategy, a role no broadcast regulator had ever anticipated and none would ever formally govern.",
  impact:{
    power:"A cable news channel becomes a direct input into military and diplomatic decisions.",
    communications:"Live, continuous coverage compresses the time between an event and a policy response.",
    tv:"A channel created as a novelty becomes indispensable to how a war is fought and watched." },
  causes:["cnn","tiananmentv"], effects:["arabspringtv"] },

{ id:"startv", year:1992, date:"1991–1999", era:6, cat:["tv","power","law"],
  title:"Star TV and the Borderless Satellite",
  wiki:"Star TV (Asian TV networks)",
  gallery:["Disney Networks Group Asia Pacific"],
  summary:"Star TV launches across Asia in 1991, beaming satellite channels from Hong Kong into more than three dozen countries regardless of national broadcasting law; Rupert Murdoch's News Corporation buys control within two years. Malaysia's state-linked ASTRO answers in 1999 by keeping satellite distribution under government control instead.",
  importance:"Star TV's footprint, beamed from the AsiaSat 1 satellite, covered a swath of Asia stretching from the Eastern Mediterranean to Japan — an enormous area in which dozens of governments had never been asked whether they wanted foreign satellite channels reaching their citizens. For India in particular, Star TV was the first large-scale arrival of foreign commercial television, entering homes through small dishes no domestic regulator had licensed and existing broadcasting law had no mechanism to address. News Corporation's 1993 acquisition made explicit what had been implicit: satellite television was a business model for crossing borders that regulation had not yet caught up to. Malaysia's response — a single government-linked satellite monopoly, ASTRO, launched in 1999 — showed the alternative: control the dish, and you control what crosses the border at all.",
  impact:{
    power:"Foreign commercial television reaches national audiences through infrastructure no domestic law anticipated.",
    law:"National broadcasting regulation has no mechanism to address satellite signals crossing its borders.",
    tv:"A single satellite service redraws the map of who can broadcast to whom." },
  causes:["eurovisionsat"], effects:["indianetneutrality"] },

{ id:"bskyb", year:1990, date:"1990–2002", era:6, cat:["tv","power"],
  title:"Europe's Pay-TV Gambles",
  wiki:"Sky Group",
  gallery:["British Satellite Broadcasting"],
  summary:"Two rival satellite broadcasters, Sky Television and British Satellite Broadcasting, merge in 1990 after both lose roughly £10 million a week — creating British Sky Broadcasting, Britain's dominant pay-TV operator. A decade later, Germany's Kirch Media bets even more heavily on pay-TV and digital rights and collapses in 2002 under roughly $10 billion in debt, Europe's largest media insolvency to that point.",
  importance:"Both stories are about the cost of building a satellite-television business from nothing. Sky and BSB had spent so heavily competing for the same British audience that merger was the only alternative to mutual bankruptcy; the combined BSkyB took six months of continued losses and a £700 million refinancing before turning around, but it survived to become the dominant force in British pay-TV, central to Rupert Murdoch's wider media reach. Leo Kirch's media group made the same bet in Germany a decade later — digital pay-TV, exclusive sports and film rights, and a proprietary decoder technology — at even larger scale, and lost: when subscriber growth fell short of the debt taken on to acquire those rights, the group collapsed in 2002, the largest media bankruptcy in European history to that point.",
  impact:{
    power:"A near-failed merger becomes the dominant force in a national pay-TV market.",
    tv:"Heavy investment in exclusive rights and proprietary technology produces Europe's largest media bankruptcy.",
    society:"Pay television proves able to build or destroy a media empire within a single decade." },
  causes:["backyarddish"], effects:[] },

{ id:"sabc", year:1994, date:"1948–1996", era:6, cat:["tv","power"],
  title:"SABC After Apartheid",
  wiki:"SABC",
  gallery:["Radio RSA"],
  summary:"The South African Broadcasting Corporation, built as an instrument of apartheid-era state messaging, is restructured ahead of the 1994 elections into a public broadcaster serving an eleven-language, multiracial democracy — a state broadcaster re-founded for the population it had previously excluded.",
  importance:"South Africa did not introduce television until 1976, decades after most developed nations, in part because the apartheid government feared its cultural influence; once introduced, SABC operated as a tightly controlled instrument of state messaging, and its international radio service, Radio RSA, broadcast the government's case to the world. Ahead of the 1994 elections that ended apartheid, SABC was restructured into an explicitly public broadcaster with a mandate to serve all eleven official languages and a newly enfranchised electorate — the most extreme version of the 'developing world' pattern in which a state broadcaster transitions toward a public-service model not gradually but as part of a complete change of political system.",
  impact:{
    power:"A broadcaster built to serve a minority government is re-founded to serve a new electorate.",
    tv:"Television policy itself had been an instrument of exclusion before it became one of inclusion.",
    society:"A multilingual public-broadcasting mandate replaces a single-audience state messaging model overnight." },
  causes:[], effects:[] },

{ id:"aljazeeratv", year:1996, date:"1996–2003", era:6, cat:["tv","power"],
  title:"Al Jazeera and the Pan-Arab Audience",
  wiki:"Al Jazeera",
  gallery:["Al Arabiya"],
  summary:"Qatar launches Al Jazeera in November 1996, the first pan-Arab news channel operating with editorial independence unusual for the region — and in 2003, Saudi-backed Al Arabiya launches from Dubai explicitly as a less provocative alternative, turning Arab satellite news into a regional competition for narrative influence.",
  importance:"Before Al Jazeera, television news across the Arab world was overwhelmingly state-run, each channel speaking to its own national audience in the framing its government preferred. Al Jazeera, funded by the Qatari government but operating with unusual editorial latitude, instead addressed a single pan-Arab audience across borders — covering stories, and giving airtime to dissidents, that domestic broadcasters elsewhere would not. Saudi Arabia's response, funding Al Arabiya's 2003 launch as an explicitly 'balanced and less provocative' alternative, confirmed that one broadcaster's framing of regional events had become a contest other governments felt compelled to enter directly — the Arab world's version of the transnational-broadcasting competition Star TV had begun in Asia.",
  impact:{
    power:"A single channel's regional framing becomes important enough that rival states fund a competitor.",
    communications:"Pan-Arab audiences gain a shared news source independent of any one national broadcaster.",
    tv:"Government-funded channels compete for regional narrative influence across borders, not within them." },
  causes:["iranrevolutiontv","cnneffect"], effects:["arabspringtv"] },

{ id:"digitaltransitionsglobal", year:2000, date:"1997–2009", era:6, cat:["tv","law"],
  title:"Four Ways to Switch Off Analog",
  wiki:"Digital terrestrial television",
  gallery:["Freeview (United Kingdom)"],
  summary:"Britain launches digital terrestrial television in 1997 (becoming Freeview), the EU adopts a coordinated Digital TV Action Plan in 1998, Japan pursues a market-led 'Ishikawa model' letting consumer adoption set the pace from 2000, and France's free-to-air TNT succeeds from 2005 where pay-TV digital models had struggled — four national strategies for the same switch from analog to digital.",
  importance:"Every broadcasting country eventually had to retire analog transmission, but the path varied by national broadcasting culture as much as by technology. Britain's Freeview offered free digital channels to anyone with a cheap receiver, succeeding partly because it cost viewers almost nothing. The EU's 1998 Action Plan tried to coordinate the timetable across member states with very different existing infrastructure. Japan's approach — sometimes called the Ishikawa model after the prefecture used as a pilot — deliberately avoided a hard national cutoff date, letting regional adoption rates determine the pace. France's TNT, launching in 2005, succeeded as a free model after earlier pay-digital satellite platforms had struggled to gain subscribers. Together they form a natural experiment: the same technical transition, run as a 'big bang' cutoff, a regional rollout, a market-led pace, and a free-to-air model, each in a different country.",
  impact:{
    tv:"The same technical transition is run as four different national experiments simultaneously.",
    law:"Coordinated regional planning and purely market-led adoption are tried side by side.",
    technology:"A free-to-air digital model succeeds where pay-television digital platforms had struggled." },
  causes:[], effects:["digitaltransition"] },

{ id:"cctvgoingout", year:2001, date:"2001–2008", era:6, cat:["tv","power"],
  title:"CCTV Goes Global",
  wiki:"China Central Television",
  gallery:["CCTV Headquarters"],
  summary:"China Central Television launches dedicated international channels from 2001 as part of a deliberate 'going out' strategy to project Chinese perspectives abroad, and in 2008 opens a $900 million Beijing headquarters — an architectural statement that state television had become a tool of soft power, not just domestic messaging.",
  importance:"For decades CCTV's mission had been entirely domestic — reaching and informing China's own population under party direction. The 'going out' strategy reversed the lens: CCTV International, later CGTN, was built to reach foreign audiences in their own languages, offering an alternative to Western networks' framing of China — an explicit echo of what Al Jazeera and Al Arabiya were doing in the Arab world for the same reasons. The new Beijing headquarters, a striking loop-shaped tower designed by a Western architecture firm, was itself part of the message: a literal monument-sized signal that Chinese state media intended to be a global institution, backed by the resources to match.",
  impact:{
    power:"State television is redirected outward, competing for influence over foreign audiences.",
    communications:"A domestic broadcaster builds a dedicated international arm to shape its country's image abroad.",
    tv:"A billion-dollar headquarters becomes itself a statement of media ambition." },
  causes:["tiananmentv"], effects:["documentno9"] },

{ id:"avmsd2007", year:2007, date:"1989–2010", era:6, cat:["tv","law","internet"],
  title:"Brussels Regulates the Stream",
  wiki:"Audiovisual Media Services Directive",
  summary:"The EU's 2007 directive renames Television Without Frontiers the Audiovisual Media Services Directive and, for the first time, extends broadcasting-style rules to on-demand 'non-linear' services — the first major regulation of what would later simply be called streaming, years before Netflix expanded into Europe.",
  importance:"By the mid-2000s, video delivered over the internet on demand — rather than broadcast on a schedule — was no longer experimental, and the EU faced the question of whether its 1989 broadcasting framework applied to it at all. The 2007 directive answered yes, in a lighter-touch form: on-demand services received a reduced set of obligations compared to linear broadcasters, covering things like protection of minors and basic advertising standards, but the principle was established that 'television-like' services delivered over the internet were not a regulatory void. Codified in 2010, it meant that when Netflix arrived in European markets from 2012 onward, it entered a market where the question of streaming regulation had already been asked — just as, across the Atlantic, the FCC was about to answer the same question in House of Cards's home market with a flat 'no.'",
  impact:{
    law:"On-demand internet video is brought inside a regulatory framework before it becomes dominant.",
    tv:"Streaming-style services are distinguished from broadcast but not left entirely unregulated.",
    power:"A regulator answers the question of streaming's legal status years before the U.S. does." },
  causes:["tvwf1989"], effects:["euquota"] },

{ id:"bbciplayer", year:2007, date:"2007–2010", era:6, cat:["tv","internet"],
  title:"The BBC Streams Itself",
  wiki:"BBC iPlayer",
  gallery:["BBC licence fee"],
  summary:"The BBC launches iPlayer in 2007, becoming the first major public broadcaster to offer its own programming on demand over the internet — even as the BBC's license fee is then frozen for six years from 2010, intensifying debate over how a public broadcaster should be funded in a streaming age.",
  importance:"Where American networks treated internet distribution warily — Hulu, launched the same year, was explicitly designed to keep video within an advertising-supported ecosystem broadcasters controlled — the BBC built iPlayer as a direct extension of its public-service remit: license-fee payers had already paid for the content, so making it available on demand required no new commercial logic. The subsequent funding freeze cut against this leadership: a public broadcaster praised for digital innovation found its primary funding mechanism politically constrained just as the cost of sustaining both broadcast and streaming operations grew. The tension — public-service ambition outrunning public-service funding — would recur across European broadcasters facing the same streaming transition.",
  impact:{
    tv:"A public broadcaster leads commercial rivals into on-demand internet distribution.",
    power:"Digital leadership does not translate into political protection for a broadcaster's funding.",
    communications:"Content funded by a universal license fee is made available on demand at no extra cost." },
  causes:["channel4uk","netflixstreaming"], effects:[] },

{ id:"arabspringtv", year:2011, date:"2003–2017", era:6, cat:["tv","power"],
  title:"Al Jazeera, Al Arabiya, and the Arab Spring",
  wiki:"Arab Spring",
  gallery:["Al Jazeera","Al Arabiya"],
  summary:"Al Jazeera's wall-to-wall coverage of the 2011 uprisings helps spread protest movements across the Arab world in real time, cementing its role as the region's dominant news voice — and six years later makes it a central target when Saudi Arabia, the UAE, Bahrain, and Egypt impose a blockade on Qatar.",
  importance:"When protests began in Tunisia in December 2010, Al Jazeera's coverage — in Arabic, available across the region via satellite, and willing to cover unrest that domestic broadcasters in Egypt, Libya, and elsewhere were ignoring or suppressing — gave protesters in one country a window into events in another, a feedback loop credited (and blamed) for the speed at which the uprisings spread. By 2017, when four Arab states cut diplomatic ties with Qatar and issued demands that explicitly included shutting Al Jazeera down, the channel's transformation from news outlet to geopolitical actor was complete: a broadcaster had become significant enough that diplomatic relations between sovereign states were conditioned, in part, on its existence.",
  impact:{
    power:"Live regional broadcasting is credited with accelerating the spread of a political movement.",
    communications:"A news channel's coverage becomes a channel of communication between protest movements in different countries.",
    tv:"A broadcaster's existence becomes a formal condition in a diplomatic and economic blockade between states." },
  causes:["aljazeeratv","cnneffect"], effects:[] },

{ id:"documentno9", year:2013, date:"2013", era:7, cat:["tv","power","surveillance"],
  title:"Document No. 9 and Entertainment Television",
  wiki:"Document Number Nine",
  summary:"A confidential 2013 Chinese Communist Party directive, 'Document No. 9,' warns against seven Western-associated ideological influences and reasserts party control over media — extending ideological screening, for the first time this explicitly, from news into entertainment programming, the genre television regulation elsewhere had mostly left alone.",
  importance:"Broadcast regulation in most of this gallery concerns news, advertising, or children's content — genres assumed to carry messages worth regulating, while entertainment is generally treated as low-stakes. Document No. 9 rejected that distinction: circulated internally in 2013, it identified entertainment media alongside news and academia as a vector for ideas the party considered dangerous — Western constitutional democracy, media independence, 'universal values' — and called for unwavering party control across all of it. Where CCTV's 'going out' strategy a decade earlier had been about projecting influence abroad, Document No. 9 was its domestic mirror: a declaration that the content controls applied to news would now apply, explicitly, to entertainment television as well.",
  impact:{
    surveillance:"Ideological screening is extended explicitly from news into entertainment programming.",
    power:"A government identifies popular entertainment, not just news, as a site of ideological risk.",
    law:"Content control is asserted as a comprehensive principle rather than genre by genre." },
  causes:["cctvgoingout","tiananmentv"], effects:[] },

{ id:"indianetneutrality", year:2016, date:"2015–2018", era:7, cat:["tv","law","internet"],
  title:"India Protects the Open Pipe",
  wiki:"Net neutrality in India",
  summary:"After more than a million public comments, India's telecom regulator bans 'zero-rating' deals that would let carriers favor certain apps' data in 2016, and the government adopts a comprehensive net-neutrality framework in 2018 — just as the United States moves the opposite way, repealing its own net-neutrality rules the year before.",
  importance:"The immediate dispute was over Facebook's 'Free Basics' program, which offered free data access to a curated set of services — critics argued this let a platform decide which parts of the internet Indians could afford to use. TRAI's 2016 ruling against zero-rating, followed by the 2018 Department of Telecommunications framework barring data discrimination outright, made India one of the strongest net-neutrality regimes in the world, with carriers risking their licenses for violations. The timing made the contrast unavoidable: as streaming video became the dominant form of mobile data traffic, India legally barred carriers from favoring any service's traffic, while the U.S. — home to most of those streaming services — removed the rule that did the same.",
  impact:{
    law:"One of the world's largest internet markets adopts a binding non-discrimination rule for data traffic.",
    power:"A platform's plan to subsidize access to itself is rejected as a threat to open competition.",
    tv:"Streaming video's growth proceeds under opposite network-neutrality regimes in two major markets." },
  causes:["startv"], effects:[] },

{ id:"singaporemedia", year:2019, date:"1972–2019", era:7, cat:["tv","law","power","surveillance"],
  title:"Singapore's Media State",
  wiki:"Protection from Online Falsehoods and Manipulation Act 2019",
  summary:"Singapore abolished its television license fee in 1972 to guarantee universal access to state-aligned broadcasting at no cost to viewers; nearly fifty years later, the 2019 'fake news' law (POFMA) gives the government power to order corrections or removals of online content — two very different tools serving the same underlying goal of a state-shaped information environment.",
  importance:"Most countries that fund television by license fee treat it as a tool for public-service independence; Singapore's 1972 abolition of the fee instead removed a financial barrier to a broadcasting system that remained closely aligned with government messaging — universal access to state-shaped content, an inversion of the BBC model that pairs the same funding mechanism with editorial independence elsewhere. POFMA, nearly half a century later, addressed a different medium toward the same end: rather than relying on broadcast licensing to shape what citizens saw, the government gained statutory power to compel corrections, labels, or removal of online content it deemed false — critics noting the law gave the executive, not courts, the first determination of falsehood. Different tools, separated by decades and technologies, aimed at the same goal: an information environment the state can shape directly.",
  impact:{
    power:"A state retains tools to shape its information environment across two very different media eras.",
    law:"Statutory authority to compel removal of online content sits with the executive rather than the courts.",
    surveillance:"Universal access and content correction serve the same underlying policy goal, decades apart." },
  causes:[], effects:[] },

{ id:"covidstreaming", year:2020, date:"2020–2021", era:7, cat:["tv","labor"],
  title:"The Pandemic Living Room",
  wiki:"Impact of the COVID-19 pandemic on television",
  summary:"COVID-19 lockdowns drive the fastest acceleration in streaming adoption in the medium's history while simultaneously halting almost all television and film production worldwide — the supply of new content collapses in the same months that demand for it spikes hardest.",
  importance:"For most of streaming's first decade, growth had been steady but gradual; in early 2020, with broadcast and cable also struggling to produce new live content from empty studios, hundreds of millions of newly homebound viewers turned to streaming libraries simultaneously, compressing years of expected subscriber growth into months. The same lockdowns that drove this demand also stopped production everywhere at once — sets closed, releases delayed, sports leagues went dark — so the surge in viewing was met largely by a library built before the pandemic, not new supply. The mismatch reshaped release strategies, including day-and-date streaming releases and abandoned theatrical windows, in ways that outlasted the lockdowns themselves.",
  impact:{
    tv:"Streaming adoption accelerates faster in months than it had in the preceding decade.",
    labor:"Television and film production halts globally and simultaneously for the first time in the medium's history.",
    society:"A surge in demand for content coincides with a near-total stop in producing it." },
  causes:["streamingwars","cordcutting"], effects:["globalstreamingmilestone"] },

{ id:"ausnewsmedia", year:2021, date:"2006–2021", era:7, cat:["tv","power","law"],
  title:"Australia Makes Platforms Pay for News",
  wiki:"News Media Bargaining Code",
  summary:"Australia relaxes media ownership rules in 2006, accelerating consolidation of its television and newspaper industries — then in 2021 reverses the flow of money entirely, becoming the first country to force Google and Meta to pay news organizations for content shared on their platforms, a 'world-first' model other governments would study.",
  importance:"The 2006 ownership relaxation let a small number of companies control television, radio, and newspapers in the same Australian city — consolidation justified at the time as necessary for media companies to survive against an emerging digital competition that, fifteen years later, turned out to be the much bigger threat. The News Media Bargaining Code addressed that threat directly: rather than regulating what platforms could show, it required Google and Meta to negotiate payment with news publishers, including broadcasters' news divisions, for the content driving traffic to their services, backed by a binding arbitration threat if negotiations failed. Roughly AU$250 million a year began flowing from platforms to Australian news media — a regulatory model immediately studied by Canada, the EU, and others as a template for rebalancing platform power.",
  impact:{
    power:"A government forces the platforms that disrupted an industry to fund the survivors directly.",
    law:"Binding arbitration, not voluntary negotiation, becomes the enforcement mechanism for platform-publisher payments.",
    tv:"Television and newspaper consolidation, encouraged as a survival strategy, precedes a much larger platform threat." },
  causes:["australiatv"], effects:[] },

{ id:"channel4debate", year:2022, date:"2011–2022", era:7, cat:["tv","power","law"],
  title:"Channel 4: Privatize, Then Don't",
  wiki:"Channel 4",
  gallery:["Leveson Inquiry"],
  summary:"The Leveson Inquiry, launched in 2011 after the phone-hacking scandal, reshapes the climate of UK media regulation even though it examined the press, not broadcasting; a decade later the government proposes privatizing the publicly owned, advertising-funded Channel 4 — and then, after sustained opposition, cancels the plan in 2022, leaving the 1982 hybrid model intact.",
  importance:"Leveson examined newspaper conduct, not television, but its findings about the relationship between media owners, politicians, and regulators shaped a decade of broader UK media-policy debate — including renewed scrutiny of whether Channel 4's unusual structure, publicly owned but commercially funded and self-financing, still made sense in a streaming-dominated market. The 2021 privatization proposal argued Channel 4 needed private capital to compete with Netflix for content; opponents argued the same independence and remit that made it valuable — the hybrid Annan Committee design from 1982 — would not survive a sale to a profit-maximizing owner. The government's 2022 reversal left the structure unchanged, a rare case of a major broadcasting privatization being proposed, debated, and abandoned within a single legislative term.",
  impact:{
    power:"A proposed privatization is reversed after the value of public ownership outweighs claimed competitive need.",
    law:"A regulatory inquiry into the press reshapes the political climate for broadcasting policy a decade later.",
    tv:"A four-decade-old hybrid public/commercial structure survives a direct challenge from the streaming era." },
  causes:["channel4uk"], effects:[] },

{ id:"canadac11", year:2023, date:"2021–2023", era:7, cat:["tv","law","power"],
  title:"Canada Regulates Streaming Like Broadcast",
  wiki:"Online Streaming Act",
  summary:"The Online Streaming Act extends Canada's decades-old broadcasting law — and its CanCon content quotas — to Netflix, Disney+, and other streaming platforms operating in Canada, requiring financial contributions to Canadian content and 'discoverability' rules ensuring Canadian programming surfaces in recommendation algorithms, not just catalogues.",
  importance:"CanCon, dating to 1970, had assumed a world of broadcast channels with finite schedules, where a quota could simply require a percentage of airtime. Streaming broke that assumption: a catalogue can contain unlimited Canadian content while an algorithm never recommends any of it. The Online Streaming Act, passed in 2023 after extensive debate over its reach, required platforms earning over CAD $10 million in Canada to register with the CRTC, contribute financially to Canadian production, and meet 'discoverability' obligations — the first major attempt anywhere to regulate not just what a streaming platform carries but how its recommendation systems surface it, extending fifty-year-old cultural-protection logic into the algorithmic age.",
  impact:{
    law:"Decades-old content quotas are extended to apply to recommendation algorithms, not just schedules.",
    power:"A streaming platform's algorithm becomes subject to cultural-policy requirements for the first time.",
    tv:"Broadcast-era protectionism is judged to require a new enforcement mechanism for the catalogue era." },
  causes:["cancon","euquota"], effects:[] },

{ id:"eudsa2024", year:2024, date:"2022–2024", era:7, cat:["tv","law","internet"],
  title:"The Digital Services Act Reaches Streaming",
  wiki:"Digital Services Act",
  summary:"The EU's Digital Services Act, fully applicable from 2024, imposes new transparency, content-moderation, and risk-assessment obligations on large online platforms — rules written mainly with social media in mind, but which apply equally to the recommendation systems and user-generated content features increasingly built into streaming services.",
  importance:"The DSA was drafted primarily to address social-media platforms, but its definitions — 'very large online platforms,' algorithmic recommendation transparency, systemic risk assessments — are broad enough to capture streaming services that have grown features once exclusive to social media: comment sections, user uploads, algorithmic 'for you' rows indistinguishable in function from a social feed's. For television regulation, the DSA represents something new: a framework that did not originate from broadcasting law at all, layering onto the AVMSD's content quotas and Television Without Frontiers's country-of-origin principle a third, internet-native regulatory regime — meaning a single streaming platform operating in the EU now answers to rules from three different regulatory traditions at once.",
  impact:{
    law:"A platform-regulation framework written for social media applies to streaming by definition, not by design.",
    tv:"Streaming services answer to broadcasting law, internet-platform law, and content-quota law simultaneously.",
    computing:"Algorithmic recommendation systems become subject to transparency requirements regardless of the content they recommend." },
  causes:["euquota","avmsd2007"], effects:[] },

{ id:"skbroadbandnetflix", year:2023, date:"2019–2025", era:7, cat:["tv","law","power"],
  title:"Who Pays for the Pipe",
  wiki:"Net neutrality",
  gallery:["Netflix"],
  summary:"South Korean ISP SK Broadband sues Netflix in 2019, demanding payment for the network capacity its traffic consumes — the world's first major legal dispute over streaming 'network usage fees' — ending in 2023 with both sides dropping their suits for a commercial partnership, even as similar fee disputes continue elsewhere into 2025.",
  importance:"Squid Game's 2021 popularity made the dispute concrete: a single hit show could spike a streaming service's share of a national network's total traffic into double digits, and SK Broadband argued Netflix should pay for that capacity the way a broadcaster pays for a transmission tower, while Netflix argued it already paid for its own connections and that ISPs were trying to charge twice for the same data. Korean courts initially sided with the ISP's right to seek payment; both companies eventually preferred a negotiated partnership to years of litigation. The underlying question — who pays when one company's content drives the bulk of another's network costs — is the same one net-neutrality rules in the US and India address from the regulatory side; Korea's courts addressed it as a private commercial dispute instead, with global streaming economics as the backdrop.",
  impact:{
    power:"A national ISP sues a global streaming service over who bears the cost of its traffic.",
    law:"Courts, not regulators, become the venue for resolving a network-cost dispute with global implications.",
    tv:"A single hit series becomes evidence in a dispute over the economics of streaming infrastructure." },
  causes:["netneutrality","cordcutting"], effects:["globalstreamingmilestone"] },

{ id:"globalstreamingmilestone", year:2026, date:"2019–2026", era:7, cat:["tv","internet"],
  title:"Streaming Overtakes Television",
  wiki:"Streaming media",
  summary:"In the United States, Nielsen's monthly 'Gauge' measurement shows streaming reaching 47.5% of all television viewing by December 2025 — eclipsing broadcast and cable combined for the first time — with the 50% threshold crossed on individual days that month and projected to become the sustained norm by mid-2026.",
  importance:"The figures are American, but the trajectory is not: streaming's share of US television viewing rose from roughly a third in 2021 to nearly half by the end of 2025, broadcast viewing fell by roughly a fifth and cable by nearly forty percent over the same years, and the underlying pattern — direct-to-consumer platforms displacing the scheduled, bundled channel as the primary way people watch — has played out, on different timelines, in every market this gallery has covered, from Britain's iPlayer-led public-broadcaster streaming to Canada's algorithm-regulating Online Streaming Act to Korea's network-fee disputes. Whether or not every market crosses 50% at once, the shift this whole section has traced — from scarce spectrum, to cable abundance, to infinite on-demand streams — reached its tipping point in the same narrow window everywhere it was measured.",
  impact:{
    tv:"The medium's primary mode of delivery changes from scheduled channels to on-demand platforms.",
    society:"A decades-long shift from scarcity to abundance to infinite choice reaches its tipping point.",
    power:"Cultural gatekeeping shifts from broadcasters and schedules to the platforms and algorithms that replaced them." },
  causes:["covidstreaming","streamingwars","skbroadbandnetflix"], effects:["streamingvoid"] }

);
